SELECT t, datacenter, sum(tx_bytesRate) AS tx_bytesRateAgg, sum(rx_bytesRate) AS rx_bytesRateAgg FROM (  SELECT t, datacenter, dc_interface, tx_bytes / (t/1000 - lagInFrame(t/1000,1,0) OVER ()) AS tx_bytesRate, rx_bytes / (t/1000 - lagInFrame(t/1000,1,0) OVER ()) AS rx_bytesRate  FROM (   SELECT (intDiv(toUInt32(event_time), 30) * 30) * 1000 AS t, datacenter, concat(datacenter, interface) AS dc_interface, max(tx_bytes) AS tx_bytes, max(rx_bytes) AS rx_bytes   FROM traffic WHERE event_date >= toDate(1735787045) AND event_date <= toDate(1735790706) AND event_time >= toDateTime(1735787045) AND event_time <= toDateTime(1735790706)   GROUP BY datacenter, dc_interface, t    ORDER BY datacenter, dc_interface, t  ) ) GROUP BY datacenter, t ORDER BY datacenter, t